<template>
    <div class="page_wrapper" :class="`lang-${lang}`">
        <NavBar />
    <div id="section-about" class="main_screen_container">
        <div class="title_container">
            <div class="title_main_container">
                <h1 class="title_main">{{ t('hero.pre') }}<span>{{ t('hero.span1') }}</span><br v-if="lang === 'ru'" />{{ t('hero.mid') }}<span>{{ t('hero.span2') }}</span>{{ t('hero.post') }}</h1>
                <p class="text_main">{{ t('hero.desc') }}</p>
            </div>
        </div>
        <button class="btn_request" @click="scrollTo('section-contacts')">{{ t('hero.btn') }}</button>
    </div>

    <div class="advantages_section">
        <span class="advantages_label advantages_label--left">{{ t('adv.left') }}</span>
        <span class="advantages_label advantages_label--right">{{ t('adv.right') }}</span>

        <div class="cards_stack">
            <div class="card card--back">
                <div class="card__image-wrap">
                    <img src="../assets/card1.png" alt="РЎРѕС‚СЂСѓРґРЅРёРє 1" class="card__image" />
                </div>
                <h3 class="card__title">{{ t('adv.c1t') }}</h3>
                <p class="card__text">{{ t('adv.c1d') }}</p>
            </div>

            <div class="card card--mid">
                <div class="card__image-wrap">
                    <img src="../assets/card2.png" alt="РЎРѕС‚СЂСѓРґРЅРёРє 2" class="card__image" />
                </div>
                <h3 class="card__title">{{ t('adv.c2t') }}</h3>
                <p class="card__text">{{ t('adv.c2d') }}</p>
            </div>

            <div class="card card--front">
                <div class="card__image-wrap">
                    <img src="../assets/card3.png" alt="РЎРѕС‚СЂСѓРґРЅРёРє 3" class="card__image" />
                </div>
                <h3 class="card__title">{{ t('adv.c3t') }}</h3>
                <p class="card__text">{{ t('adv.c3d') }}</p>
            </div>
        </div>
    </div>

    <section id="section-projects" class="works_section">
        <h2 class="works_title">{{ t('works.title') }}</h2>

        <div class="works_nav">
            <button class="works_nav__btn works_nav__btn--prev" aria-label="РќР°Р·Р°Рґ" @click="prev">
                <svg width="50" height="50" viewBox="0 0 50 50" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path d="M25 0C38.8071 4.12325e-06 50 11.1929 50 25C50 38.8071 38.8071 50 25 50C11.1929 50 4.12352e-06 38.8071 0 25C0 11.1929 11.1929 0 25 0ZM27.4141 11.9189C26.6331 11.1381 25.367 11.1383 24.5859 11.9189L12.9199 23.585C12.1389 24.366 12.139 25.632 12.9199 26.4131L24.5859 38.0801C25.3669 38.8611 26.633 38.861 27.4141 38.0801C28.1948 37.299 28.195 36.0329 27.4141 35.252L19.1621 26.999H37.667C38.7715 26.9989 39.667 26.1035 39.667 24.999C39.6666 23.8949 38.7712 22.9991 37.667 22.999H19.1621L27.4141 14.7471C28.1948 13.966 28.195 12.6999 27.4141 11.9189Z" fill="#0F0F14"/>
                </svg>
            </button>
            <button class="works_nav__btn works_nav__btn--next" aria-label="Р'РїРµСЂС'Рґ" @click="next">
                <svg width="50" height="50" viewBox="0 0 50 50" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path d="M25 0C11.1929 4.12325e-06 0 11.1929 0 25C3.8147e-06 38.8071 11.1929 50 25 50C38.8071 50 50 38.8071 50 25C50 11.1929 38.8071 0 25 0ZM23.5859 11.9189C24.3669 11.1381 25.633 11.1383 26.4141 11.9189L38.0801 23.585C38.8611 24.366 38.861 25.632 38.0801 26.4131L26.4141 38.0801C25.6331 38.8611 24.367 38.861 23.5859 38.0801C22.8052 37.299 22.805 36.0329 23.5859 35.252L31.8379 26.999H13.333C12.2285 26.9989 11.333 26.1035 11.333 24.999C11.3334 23.8949 12.2288 22.9991 13.333 22.999H31.8379L23.5859 14.7471C22.8052 13.966 22.805 12.6999 23.5859 11.9189Z" fill="#0F0F14"/>
                </svg>
            </button>
        </div>

        <div
            class="works_track"
            :style="trackStyle"
            @transitionend="onTransitionEnd"
        >
            <div
                v-for="(p, i) in allProjects"
                :key="i"
                class="work_deck"
            >
                <div class="work_card wc-back" :class="`work_card--${p.id}`">
                    <div class="work_card__image"><img :src="p.imgBack" :alt="t('works.' + p.id)" /></div>
                    <div class="work_card__footer" :class="`work_card__footer--${p.lines}line`">
                        <span class="work_card__label">{{ getProjectTitle(p) || t('works.' + p.id) }}</span>
                    </div>
                </div>
                <div class="work_card wc-front" :class="`work_card--${p.id}`">
                    <div class="work_card__image"><img :src="p.imgFront" :alt="t('works.' + p.id)" /></div>
                    <div class="work_card__footer" :class="`work_card__footer--${p.lines}line`">
                        <span class="work_card__label">{{ getProjectTitle(p) || t('works.' + p.id) }}</span>
                    </div>
                    <router-link class="work_card__btn" :to="`/work/${p.id}`">{{ t('works.case') }} <svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M1 9L9 1M9 1H2M9 1V8" stroke="#EAF0F6" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg></router-link>
                </div>
            </div>
        </div>
    </section>

    <section id="section-pricing" class="calc_section" :style="{ height: calcSectionHeight }">
        <h2 class="calc_title">{{ t('calc.title') }}</h2>
        <p class="calc_desc">{{ t('calc.desc') }}</p>

        <div class="calc_widget">
            <div class="calc_display">
                <span>{{ t('calc.sum') }} {{ calcPriceFormatted }} {{ t('calc.currency') }}</span>
            </div>
            <div class="calc_numpad">
                <div v-for="(row, ri) in calcKeys" :key="ri" class="calc_row">
                    <button
                        v-for="key in row"
                        :key="key"
                        class="calc_key"
                        :class="calcKeyClass(key)"
                    >{{ key }}</button>
                </div>
            </div>
        </div>

        <div class="calc_options">
            <div class="calc_group">
                <h3 class="calc_group__title">{{ t('calc.servicesQ') }}</h3>
                <p class="calc_group__hint">{{ t('calc.servicesHint') }}</p>
                <div class="calc_chips">
                    <button
                        v-for="s in calcServices"
                        :key="s.id"
                        class="calc_chip"
                        :class="{ 'calc_chip--active': s.selected }"
                        @click="s.selected = !s.selected"
                    >{{ t('service.' + s.id) }}</button>
                </div>
            </div>

            <div v-if="showServiceOptions" class="calc_group">
                <h3 class="calc_group__title">{{ t('calc.realizationQ') }}</h3>
                <div class="calc_chips">
                    <button
                        v-for="r in calcRealizations"
                        :key="r.id"
                        class="calc_chip"
                        :class="{ 'calc_chip--active': selectedRealization === r.id }"
                        @click="selectedRealization = r.id"
                    >{{ t('real.' + r.id) }}</button>
                </div>
            </div>

            <div v-if="showServiceOptions" class="calc_group">
                <h3 class="calc_group__title">{{ t('calc.selectVariantQ') }}</h3>
                <div v-for="serviceId in selectedServices" :key="serviceId" class="calc_subgroup">
                    <h4 class="calc_subgroup__title">{{ t('service.' + serviceId) }}</h4>
                    <div class="calc_chips">
                        <button
                            v-for="option in currentServiceOptions[serviceId]"
                            :key="option.id"
                            class="calc_chip"
                            :class="{ 'calc_chip--active': selectedServiceOption[serviceId] === option.id }"
                            @click="selectedServiceOption[serviceId] = option.id"
                        >{{ t('option.' + serviceId + '.' + option.id) }}</button>
                    </div>
                </div>
            </div>
        </div>
    </section>

    <section id="section-contacts" class="order_section">
        <h2 class="order_title" style="white-space: pre-line">{{ t('order.title') }}</h2>

        <div class="order_person">
            <svg width="455" height="451" viewBox="0 0 455 451" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path d="M223.729 119.458C225.009 119.964 226.422 120.256 227.975 120.29C236.424 120.472 240.897 112.455 242.131 103.886C242.131 103.886 237.884 102.213 234.699 102.237C226.444 102.298 223.729 119.458 223.729 119.458Z" fill="#0F0F14"/>
