            </svg>
        </div>

        <form class="order_form" @submit.prevent="submitOrder">

            <div class="order_group">
                <h3 class="order_group__title">{{ t('order.servicesQ') }}</h3>
                <p class="order_group__hint">{{ t('order.servicesHint') }}</p>
                <div class="order_chips">
                    <button
                        v-for="s in orderServices"
                        :key="s.id"
                        class="order_chip"
                        :class="{ 'order_chip--active': s.selected }"
                        @click="s.selected = !s.selected"
                    >{{ t('service.' + s.id) }}</button>
                </div>
            </div>

            <div class="order_group">
                <h3 class="order_group__title">{{ t('order.budgetQ') }}</h3>
                <p class="order_group__hint">{{ t('order.budgetHint') }}</p>
                <div class="order_chips">
                    <button
                        v-for="b in orderBudgets"
                        :key="b.id"
                        class="order_chip"
                        :class="{ 'order_chip--active': selectedBudget === b.id }"
                        @click="selectedBudget = b.id"
                    >{{ t('budget.' + b.id) }}</button>
                </div>
            </div>

            <div class="order_field">
                <div class="order_field__row">
                    <input v-model="orderForm.task"    class="order_input" :placeholder="t('order.taskPh')" />
                    <span class="order_field__opt">{{ t('order.opt') }}</span>
                </div>
                <div class="order_field__line"></div>
            </div>

            <div class="order_field">
                <div class="order_field__row">
                    <input v-model="orderForm.company" class="order_input" :placeholder="t('order.companyPh')" />
                    <span class="order_field__opt">{{ t('order.opt') }}</span>
                </div>
                <div class="order_field__line"></div>
            </div>

            <div class="order_field">
                <div class="order_field__row">
                    <input v-model="orderForm.name" class="order_input" :placeholder="t('order.namePh')" @focus="orderErrors.name = ''" />
                </div>
                <div class="order_field__line"></div>
                <div v-if="orderErrors.name" class="order_error">{{ orderErrors.name }}</div>
            </div>

            <div class="order_field">
                <div class="order_field__row">
                    <input v-model="orderForm.contact" class="order_input" :placeholder="t('order.contactPh')" @focus="orderErrors.contact = ''" />
                </div>
                <div class="order_field__line"></div>
                <div v-if="orderErrors.contact" class="order_error">{{ orderErrors.contact }}</div>
            </div>

            <button type="submit" class="order_submit" :disabled="!orderForm.name || !orderForm.contact || orderSubmitting" :class="{ 'order_submit--success': orderSubmitted }">
                {{ orderSubmitted ? 'Заявка оформлена' : (orderSubmitting ? 'Отправляем...' : t('order.submit')) }}
            </button>

            <p class="order_privacy">
                {{ t('order.p1') }}<a href="#" class="order_privacy__link">{{ t('order.pl1') }}</a>{{ t('order.p2') }}<a href="#" class="order_privacy__link">{{ t('order.pl2') }}</a>
            </p>
        </form>
    </section>

    <footer class="footer_section">
        <div class="footer_ellipse">
            <svg width="987" height="508" viewBox="0 0 987 508" fill="none" xmlns="http://www.w3.org/2000/svg">
