</template>

<script>
import woomeeImg  from '../assets/woomee.png'
import agenda1Img from '../assets/agenda1.png'
import agenda2Img from '../assets/agenda2.png'
import tigerImg   from '../assets/tiger.png'
import botImg     from '../assets/bot.png'
import { mapState, mapActions } from 'pinia'
import { useI18nStore } from '../stores/i18n'
import NavBar from '../components/NavBar.vue'

const SLOT = 400

export default {
    components: { NavBar },
    data() {
        const projects = [
            { id: 'woomee', imgBack: woomeeImg,  imgFront: woomeeImg,  lines: 1 },
            { id: 'agenda', imgBack: agenda2Img, imgFront: agenda1Img, lines: 2 },
            { id: 'tiger',  imgBack: tigerImg,   imgFront: tigerImg,   lines: 1 },
            { id: 'bot',    imgBack: botImg,      imgFront: botImg,     lines: 1 },
        ]
        return {
            projects,
            activeSection: 'section-about',
            trackOffset: -(projects.length * SLOT),
            animated: true,

            calcServices: [
                { id: 'brand',      price: 15000, selected: false },
                { id: 'logo',       price: 20000, selected: true  },
                { id: 'web_design', price: 30000, selected: false },
                { id: 'app_design', price: 40000, selected: false },
                { id: 'landing',    price: 35000, selected: false },
                { id: 'website',    price: 50000, selected: false },
                { id: 'shop',       price: 70000, selected: false },
                { id: 'consult',    price: 5000,  selected: false },
            ],
            calcRealizations: [
                { id: 'new',     mult: 1.0 },
                { id: 'update',  mult: 0.6 },
                { id: 'rebrand', mult: 0.8 },
            ],
            calcServiceOptions: {
                brand: {
                    new: [
                        { id: 'letter', price: 15000 },
                        { id: 'assoc', price: 25000 },
                        { id: 'combo', price: 20000 }
                    ],
                    update: [
                        { id: 'letter', price: 10000 },
                        { id: 'assoc', price: 15000 },
                        { id: 'combo', price: 12000 }
                    ],
                    rebrand: [
                        { id: 'letter', price: 15000 },
                        { id: 'assoc', price: 25000 },
                        { id: 'combo', price: 20000 }
                    ]
                },
                logo: {
                    new: [
                        { id: 'letter', price: 15000 },
                        { id: 'assoc', price: 25000 },
                        { id: 'combo', price: 20000 }
                    ],
                    update: [
                        { id: 'letter', price: 10000 },
                        { id: 'assoc', price: 15000 },
                        { id: 'combo', price: 12000 }
                    ],
                    rebrand: [
                        { id: 'letter', price: 15000 },
                        { id: 'assoc', price: 25000 },
                        { id: 'combo', price: 20000 }
                    ]
                },
                web_design: {
                    new: [
                        { id: 'full', price: 30000 },
                        { id: 'ui', price: 25000 },
                        { id: 'ux', price: 20000 }
                    ],
                    update: [
                        { id: 'full', price: 18000 },
                        { id: 'ui', price: 15000 },
                        { id: 'ux', price: 12000 }
                    ],
                    rebrand: [
                        { id: 'full', price: 24000 },
                        { id: 'ui', price: 20000 },
                        { id: 'ux', price: 16000 }
                    ]
                },
                app_design: {
                    new: [
                        { id: 'full', price: 40000 },
                        { id: 'ui', price: 30000 },
                        { id: 'ux', price: 25000 }
                    ],
                    update: [
                        { id: 'full', price: 24000 },
                        { id: 'ui', price: 18000 },
                        { id: 'ux', price: 15000 }
                    ],
                    rebrand: [
                        { id: 'full', price: 32000 },
                        { id: 'ui', price: 24000 },
                        { id: 'ux', price: 20000 }
                    ]
                },
                landing: {
                    new: [
                        { id: 'landing', price: 35000 }
                    ],
                    update: [
                        { id: 'landing', price: 21000 }
                    ],
                    rebrand: [
                        { id: 'landing', price: 28000 }
                    ]
                },
                website: {
                    new: [
                        { id: 'corporate', price: 50000 },
                        { id: 'magazine', price: 60000 },
                        { id: 'portal', price: 70000 }
                    ],
                    update: [
                        { id: 'corporate', price: 30000 },
                        { id: 'magazine', price: 36000 },
                        { id: 'portal', price: 42000 }
                    ],
                    rebrand: [
                        { id: 'corporate', price: 40000 },
                        { id: 'magazine', price: 48000 },
                        { id: 'portal', price: 56000 }
                    ]
                },
                shop: {
                    new: [
                        { id: 'shop', price: 70000 }
                    ],
                    update: [
                        { id: 'shop', price: 42000 }
                    ],
                    rebrand: [
                        { id: 'shop', price: 56000 }
                    ]
                },
                consult: {
                    new: [
                        { id: 'identity', price: 5000 },
                        { id: 'design', price: 5000 },
                        { id: 'audit_site', price: 5000 },
                        { id: 'audit_app', price: 5000 }
                    ],
                    update: [
                        { id: 'identity', price: 3000 },
                        { id: 'design', price: 3000 },
                        { id: 'audit_site', price: 3000 },
                        { id: 'audit_app', price: 3000 }
                    ],
                    rebrand: [
                        { id: 'identity', price: 4000 },
                        { id: 'design', price: 4000 },
                        { id: 'audit_site', price: 4000 },
                        { id: 'audit_app', price: 4000 }
                    ]
                }
            },
            selectedRealization: 'new',
            selectedServiceOption: {},  // { serviceId: optionId }
            calcKeys: [
                ['CE', 'C', '%', '÷'],
                ['7',  '8', '9', '×'],
                ['4',  '5', '6', '−'],
                ['1',  '2', '3', '+'],
                ['±', '0', ',', '='],
            ],

            orderServices: [
                { id: 'brand',      selected: false },
                { id: 'logo',       selected: false },
                { id: 'web_design', selected: false },
                { id: 'app_design', selected: false },
                { id: 'landing',    selected: false },
                { id: 'website',    selected: false },
                { id: 'shop',       selected: false },
                { id: 'consult',    selected: false },
                { id: 'other',      selected: false },
            ],
            orderBudgets: [
                { id: 'b1' }, { id: 'b2' }, { id: 'b3' }, { id: 'b4' }, { id: 'b5' },
            ],
            selectedBudget: null,
            orderForm: { task: '', company: '', name: '', contact: '' },
            orderSubmitting: false,
            orderSubmitted: false,
            orderErrors: { name: '', contact: '' },
            exchangeRates: { usd: 95, eur: 105 },
            lastRatesFetch: null,
        }
    },
    computed: {
        ...mapState(useI18nStore, ['lang']),
        currentLang() { return this.lang },
        allProjects() {
            return [...this.projects, ...this.projects, ...this.projects]
        },
        trackStyle() {
            return {
                transform: `translateX(${this.trackOffset}px)`,
                transition: this.animated ? 'transform 0.5s ease' : 'none',
            }
        },
        calcPrice() {
            let base = this.calcServices
                .filter(s => s.selected)
                .reduce((sum, s) => sum + s.price, 0)
            if (base === 0) return 0

            // Добавляем цены выбранных опций для каждой услуги
            this.selectedServices.forEach(serviceId => {
                const optionId = this.selectedServiceOption[serviceId]
                if (optionId) {
                    const option = this.calcServiceOptions[serviceId]?.[this.selectedRealization]?.find(o => o.id === optionId)
                    if (option) {
                        base += option.price
                    }
                }
            })

            const r = this.calcRealizations.find(r => r.id === this.selectedRealization)
            return Math.round(base * (r?.mult ?? 1))
        },
        calcPriceFormatted() {
            if (this.calcPrice === 0) return '0'
            const locales = {
                ru: 'ru-RU',
                en: 'en-US',
                es: 'es-ES'
            }
            const rates = {
                ru: 1,
                en: this.exchangeRates.usd,
                es: this.exchangeRates.eur
            }
            const rate = rates[this.lang] || 1
            const locale = locales[this.lang] || 'ru-RU'
            const convertedPrice = Math.round(this.calcPrice * rate)
            return convertedPrice.toLocaleString(locale)
        },
        selectedServices() {
            return this.calcServices.filter(s => s.selected).map(s => s.id)
        },
        showServiceOptions() {
            return this.selectedServices.length > 0
        },
        currentServiceOptions() {
            const options = {}
            this.selectedServices.forEach(serviceId => {
                options[serviceId] = (this.calcServiceOptions[serviceId]?.[this.selectedRealization]) || []
            })
            return options
        },
        calcSectionHeight() {
            if (!this.showServiceOptions) return '831px'
            // Базовая высота + раздел реализации (50px) + по 97px за каждую услугу
            const servicesHeight = this.selectedServices.length * 97
            const totalHeight = 831 + 50 + servicesHeight
            return totalHeight + 'px'
        },
    },
    mounted() {
        this.loadProjects()
        this.fetchExchangeRates()

        const ids = ['section-about', 'section-projects', 'section-pricing', 'section-contacts']
        this._onScroll = () => {
            const mid = window.scrollY + window.innerHeight / 2
            let closest = ids[0]
            let minDist = Infinity
            ids.forEach(id => {
                const el = document.getElementById(id)
                if (!el) return
                const dist = Math.abs(el.offsetTop + el.offsetHeight / 2 - mid)
                if (dist < minDist) { minDist = dist; closest = id }
            })
            this.activeSection = closest
        }
        window.addEventListener('scroll', this._onScroll, { passive: true })
        this._onScroll()

        const sectionId = this.$route.query.scroll
        if (sectionId && ['section-about', 'section-projects', 'section-pricing', 'section-contacts'].includes(sectionId)) {
            this.$nextTick(() => {
                document.getElementById(sectionId)?.scrollIntoView({ behavior: 'smooth' })
            })
        }
    },
    beforeUnmount() {
        window.removeEventListener('scroll', this._onScroll)
    },
    methods: {
        next() { this.trackOffset -= SLOT },
        prev() { this.trackOffset += SLOT },
        onTransitionEnd() {
            const N = this.projects.length
            if (this.trackOffset <= -(N * 2) * SLOT) {
                this.animated = false
                this.trackOffset += N * SLOT
                this.$nextTick(() => { this.animated = true })
            } else if (this.trackOffset >= 0) {
                this.animated = false
                this.trackOffset -= N * SLOT
                this.$nextTick(() => { this.animated = true })
            }
        },
        ...mapActions(useI18nStore, ['t', 'setLang']),
        calcKeyClass(key) {
            const ops = [this.calcKeys[0][3], this.calcKeys[1][3], this.calcKeys[2][3], '+', '%']
            const fns = ['CE', 'C', this.calcKeys[4][0], ',']
            return {
                'calc_key--op': ops.includes(key),
                'calc_key--eq': key === '=',
                'calc_key--fn': fns.includes(key),
            }
        },
        scrollTo(id) {
            document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' })
        },
        getLocalizedText(project, field) {
            const currentLang = this.lang || 'ru'
            return project[`${field}_${currentLang}`] || project[`${field}_ru`] || ''
        },
        getProjectTitle(project) {
            return this.getLocalizedText(project, 'title')
        },
        getProjectSubtitle(project) {
            return this.getLocalizedText(project, 'subtitle')
        },
        async loadProjects() {
            try {
                const response = await fetch('http://localhost:5000/api/projects')
                const dbProjects = await response.json()
                console.log('Loaded projects from DB:', dbProjects)

                if (Array.isArray(dbProjects) && dbProjects.length > 0) {
                    const ensureUrl = (path) => {
                        if (!path) return ''
                        if (path.startsWith('http')) return path
                        return `http://localhost:5000${path}`
                    }

                    this.projects = dbProjects.map(p => ({
                        id: p.id,
                        imgBack: ensureUrl(p.secondary_image) || ensureUrl(p.main_image),
                        imgFront: ensureUrl(p.main_image),
                        lines: p.subtitle_ru && p.subtitle_ru.length > 30 ? 2 : 1,
                        name: p.name,
                        ...p // Keep all original data for WorkDetail
                    }))
                    console.log('Processed projects for display:', this.projects)
                    this.trackOffset = -(this.projects.length * SLOT)
                }
            } catch (error) {
                console.error('Error loading projects:', error)
            }
        },
        async fetchExchangeRates() {
            const now = Date.now()
            if (this.lastRatesFetch && now - this.lastRatesFetch < 3600000) return

            try {
                const response = await fetch('https://api.exchangerate-api.com/v4/latest/RUB')
                const data = await response.json()

                if (data.rates) {
                    this.exchangeRates = {
                        usd: data.rates.USD,
                        eur: data.rates.EUR
                    }
                    this.lastRatesFetch = now
                    console.log('Updated exchange rates:', this.exchangeRates)
                }
            } catch (error) {
                console.warn('Failed to fetch exchange rates, using defaults:', error)
            }
        },
        async submitOrder() {
            this.orderErrors = { name: '', contact: '' }

            if (!this.orderForm.name || !this.orderForm.name.trim()) {
                this.orderErrors.name = 'Пожалуйста, введите ваше имя'
                return
            }
            if (!this.orderForm.contact || !this.orderForm.contact.trim()) {
                this.orderErrors.contact = 'Пожалуйста, введите контакт'
                return
            }

            this.orderSubmitting = true

            try {
                const selectedServices = this.orderServices
                    .filter(s => s.selected)
                    .map(s => this.t('service.' + s.id))
                    .join(', ')

                const payload = {
                    task: this.orderForm.task || '',
                    company: this.orderForm.company || '',
                    name: this.orderForm.name.trim(),
                    contact: this.orderForm.contact.trim(),
                    services: selectedServices,
                    budget: this.selectedBudget,
                }

                console.log('Submitting order:', payload)

                const response = await fetch('http://localhost:5000/api/leads', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(payload),
                })

                console.log('Response status:', response.status)
                const responseData = await response.json()
                console.log('Response data:', responseData)

                if (response.ok) {
                    this.orderSubmitted = true
                    this.orderForm = { task: '', company: '', name: '', contact: '' }
                    this.orderServices.forEach(s => s.selected = false)
                    this.selectedBudget = null
                    this.orderErrors = { name: '', contact: '' }

                    setTimeout(() => {
                        this.orderSubmitted = false
                    }, 3000)
                }
            } catch (error) {
                console.error('Error submitting order:', error)
            } finally {
                this.orderSubmitting = false
            }
        },
    },
}
</script>

