    border: 1px solid #EAF0F6;
    backdrop-filter: blur(10px);
    border-radius: 30px;
    padding: 35px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 30px;
    transition: transform 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.card--back {
    transform: rotate(-9deg);
}

.card--mid {
    transform: rotate(9.75deg);
}

.card--front {
    transform: none;
}

.cards_stack:hover .card--back {
    transform: translateX(-540px) rotate(-9deg);
}

.cards_stack:hover .card--mid {
    transform: translateX(540px) rotate(9deg);
}

.cards_stack:hover .card--front {
    transform: translateY(-30px);
}

.card__image-wrap {
    width: 420px;
    height: 300px;
    background: #EAF0F6;
    border-radius: 30px;
    overflow: hidden;
}

.card__image {
