}

.card__title {
    margin: 0;
    font-family: 'Gilroy';
    font-style: normal;
    font-weight: 800;
    font-size: 32px;
    line-height: 100%;
    text-align: center;
    color: #EAF0F6;
}

.card--back .card__title,
.card--mid .card__title {
    color: #FFFFFF;
}

.card__text {
    margin: 0;
    font-family: 'Gilroy';
    font-style: normal;
    font-weight: 600;
    font-size: 20px;
    line-height: 120%;
    color: #EAF0F6;
}

