/* ========================
   HERO — мобильный топбар
   ======================== */
@media (max-width: 1300px) {
    .main_screen_container {
        height: calc(100vh - 60px);
        min-height: 500px;
        justify-content: center;
        padding: 40px 20px 40px;
    }

    .title_container {
        background-image: none;
        margin-top: 0;
        width: 100%;
        height: auto;
        display: flex;
        justify-content: center;
    }

    .title_main_container {
        width: 100%;
        max-width: 800px;
        height: auto;
        margin-top: 0;
        gap: 20px;
        padding: 0;
    }

    .btn_request {
        margin-top: 40px;
    }
}

/* ========================
   Все устройства ниже 1920px — ширина секций
   ======================== */
@media (max-width: 1920px) {
    .advantages_section,
    .works_section,
    .calc_section,
    .order_section,
    .footer_section {
        width: 100%;
    }
}

@media (max-width: 1919px) {
    .footer_ellipse { display: none; }

    /* Футер — flexbox с двумя колонками */
    .footer_section {
        height: auto;
        display: flex;
        flex-direction: row;
        align-items: flex-start;
        justify-content: space-between;
        padding: 49px 5% 50px;
        gap: 60px;
        overflow: visible;
    }

    /* Левая колонка: legal + copyright */
    .footer_col_left {
        flex: 1;
        min-width: 0;
        display: flex;
        flex-direction: column;
    }

    .footer_legal {
        position: static;
        left: auto; top: auto;
        width: auto;
    }

    .footer_copyright {
        position: static;
        left: auto; bottom: auto;
        margin-top: 40px;
        display: block;
    }

    /* Правая колонка: карточка без рамки */
    .footer_card {
        position: static;
        left: auto; right: auto; top: auto;
        flex-shrink: 0;
        width: 280px;
        height: auto;
        background: none;
        border: none;
        backdrop-filter: none;
        border-radius: 0;
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: 0;
    }

    .footer_card__frame { display: none; }

    .footer_card__logo {
        position: static;
        left: auto; top: auto;
        transform: none;
        width: 160px;
        height: auto;
        margin-bottom: 20px;
    }

    .footer_card__logo img {
        height: 120px;
        width: auto;
    }

    .footer_card__divider {
        position: static;
        left: auto; top: auto;
        width: 100%;
        margin-bottom: 16px;
    }

    .footer_card__social_title {
        position: static;
        left: auto; top: auto;
        width: auto;
        font-size: 20px;
        margin-bottom: 20px;
    }

    .footer_card__socials {
        position: static;
        transform: none;
        bottom: auto; left: auto;
        justify-content: center;
    }
}

/* ========================
   Pro Display XDR и ниже (≤ 1600px)
   ======================== */
@media (max-width: 1600px) and (min-width: 1401px) {
    /* Надписи преимуществ */
    .advantages_label--left  { left: 4%; }
    .advantages_label--right { left: auto; right: 4%; }

    /* Проекты — оставляем оригинальный вид, только двигаем кнопки */
    .works_nav { left: auto; right: 40px; }

    /* Калькулятор — оставляем оригинальный вид, сдвигаем описание и опции */
    .calc_desc { left: auto; right: 40px; width: 300px; }
    .calc_options { width: calc(100% - 880px); }

    /* Заявки — оригинальный вид, форма прижата вправо */
    .order_form { left: auto; right: 20px; width: calc(100% - 860px); }
    .order_submit { width: 100%; }

    /* Футер — оригинальный вид, карточка прижата вправо */
    .footer_card { left: auto; right: 40px; }
    .footer_ellipse { display: none; }
    .footer_row { flex-direction: column; gap: 4px; }
    .footer_contact_row { flex-direction: column; align-items: flex-start; gap: 4px; }
    .footer_contact_desc { text-align: left; max-width: none; }
}

/* ========================
   iMac / Studio Display (≤ 1600px)
   ======================== */
@media (max-width: 1600px) and (min-width: 1101px) {
    .card {
        width: 360px;
        height: 430px;
        padding: 24px;
        gap: 18px;
    }
    .card__image-wrap {
        width: 100%;
        height: 210px;
